.darma-loader-darma-custom-134 {
  color: #7c3aed;
width: 49px;
aspect-ratio: 1;
--c:no-repeat linear-gradient(135deg,currentColor,var(--loader-secondary-color));
background: var(--c), var(--c), var(--c), var(--c), var(--c), var(--c);
animation:
darma-loader-darma-custom-134-l14-1 .5s infinite alternate,
darma-loader-darma-custom-134-l14-2 2s infinite;
}
@keyframes darma-loader-darma-custom-134-l14-1 {
0%,10% {background-size:20% 100%}
100% {background-size:20% 20%}
}
@keyframes darma-loader-darma-custom-134-l14-2 {
0%,49.9% {background-position: 0 0 ,0 100%,50% 50%,50% 50% ,100% 0 ,100% 100%}
50%,100% {background-position: 0 50%,0 50%,50% 0 ,50% 100%,100% 50%,100% 50% }
}

